from agent import *from models.products import *import simplejsondef run(context, session):    session.queue(Request("https://guitar.com/reviews/page/1", use="curl", force_charset='utf-8', max_age=0), process_revlist, dict())def process_revlist(data, context, session):    revs = data.xpath('//div[@class="relative"][h3]')    for rev in revs:        title = rev.xpath('h3/text()').string()        url = rev.xpath('a/@href').string()        session.queue(Request(url, use="curl", force_charset='utf-8', max_age=0), process_review, dict(context, title=title, url=url))    next_url = data.xpath('//a[span[contains(., "Next") or contains(., "Read More")]]/@href').string()    if next_url:        session.queue(Request(next_url, use="curl", force_charset='utf-8', max_age=0), process_revlist, dict(context))def process_review(data, context, session):    product = Product()    product.name = context["title"]    product.url = context["url"]    product.category = 'Guitars|'    product.ssid = product.url.split('/')[-2]    review = Review()    review.title = context["title"]    review.url = product.url    review.type = 'pro'    review.ssid = product.ssid    rev_json = data.xpath('''//script[contains(., '"@type":"ReviewNewsArticle"')]/text()''').string()    if rev_json:        rev_json = simplejson.loads(rev_json).get('@graph', [{}])[0]        name = rev_json.get('itemReviewed', {}).get('name')        if name:            product.name = name        date = rev_json.get('datePublished')        if date:            review.date = date.split('T')[0]        cats = rev_json.get('keywords')        if cats:            for cat in cats:                product.category += cat + '/'        product.category = product.category.rstrip('/|')    author = data.xpath('//a[contains(@href, "author/")]').first()    if author:        author_name = author.xpath('text()').string()        author_url = author.xpath('@href').string()        author_ssid = author_url.split('/')[-2]        review.authors.append(Person(name=author_name, profile_url=author_url, ssid=author_ssid))    grade_overall = data.xpath('//h4[contains(., "Our rating")]/following-sibling::h4/text()').string()    if grade_overall:        review.grades.append(Grade(type='overall', value=float(grade_overall), best=10.0))    summary = data.xpath('//div[@class="w-full"]/div/p/text()').string()    if not summary:        summary = data.xpath('//meta[@name="description"]/@content').string()    if summary:        review.add_property(type='summary', value=summary)    conclusion = data.xpath('//h4[contains(., "verdict")]/following-sibling::div/text()').string()    if not conclusion:        conclusion = data.xpath('//h2[contains(., "Verdict")]/following-sibling::p[1]/text()').string()    if conclusion:        review.properties.append(ReviewProperty(type='conclusion', value=conclusion))    excerpt = data.xpath('//div[@class="prose-lg prose"]/p[not(preceding-sibling::h2[regexp:test(., "verdict", "i")])]//text()').string(multiple=True)    if excerpt:        review.add_property(type='excerpt', value=excerpt)        product.reviews.append(review)        session.emit(product)